def build_index_from_json_documents(
    json_file_path: str,
    index_path: str,
    text_field: str = "text",
    metadata_fields: Optional[List[str]] = None,
    backend_name: str = "hnsw"
) -> str:
    # Check if JSON file exists
    if not Path(json_file_path).exists():
        raise FileNotFoundError(f"JSON file not found: {json_file_path}")

    # Load JSON data
    try:
        with open(json_file_path, encoding='utf-8') as f:
            data = json.load(f)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON file")

    # Validate data structure and check for text_field
    if not isinstance(data, list):
        raise ValueError("Invalid JSON format: expected list")

    for i, doc in enumerate(data):
        if not isinstance(doc, dict):
            raise ValueError(f"Document {i} is not a dictionary")
        if text_field not in doc:
            raise ValueError(f"Missing required field '{text_field}' in document {i}")

    # Process documents for LeannBuilder
    processed_docs = []
    for i, doc in enumerate(data):
        text = doc[text_field]
        # Handle metadata
        if metadata_fields is None:
            metadata = {k: v for k, v in doc.items() if k != text_field}
        else:
            metadata = {field: doc.get(field) for field in metadata_fields}
        processed_docs.append({
            'id': str(i),
            'text': text,
            'metadata': metadata
        })

    # Build the index
    builder = LeannBuilder(backend_module_name=backend_name)
    builder.build_index(processed_docs, index_path)

    return index_path

