def merge_search_results(
    results_by_index: Dict[str, List[SearchResult]],
    global_top_k: int = 10,
    deduplicate: bool = True
) -> List[SearchResult]:
    merged = []
    for res_list in results_by_index.values():
        merged.extend(res_list)
    sorted_merged = sorted(merged, key=lambda x: x.score, reverse=True)
    if deduplicate:
        seen_texts = set()
        deduped = []
        for res in sorted_merged:
            text = res.text
            if text not in seen_texts:
                seen_texts.add(text)
                deduped.append(res)
        sorted_merged = deduped
    return sorted_merged[:global_top_k]

