def get_index_statistics(index_path: str) -> dict[str, Any]:
    index_meta_path = f"{index_path}.meta.json"
    if not Path(index_meta_path).exists():
        raise FileNotFoundError(f"LEANN metadata file not found at {index_meta_path}")

    with open(index_meta_path) as f:
        meta = json.load(f)
    passage_sources = meta.get("passage_sources", [])

    total_passages = 0
    metadata_fields = set()
    field_value_counts = defaultdict(Counter)

    for passage_source in passage_sources:
        with open(passage_source) as f:
            for line_num, line in enumerate(f, 1):
                passage = json.loads(line.strip())
                metadata = passage.get("metadata", {})

                for key in metadata:
                    metadata_fields.add(key)
                    field_value_counts[key][metadata[key]] += 1

                total_passages += 1

    # Convert defaultdict(Counter) to regular dict of dicts
    field_value_counts = {k: dict(v) for k, v in field_value_counts.items()}

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(metadata_fields),
        "field_value_counts": field_value_counts,
    }

def analyze_index_coverage(index_path: str, required_fields: List[str]) -> dict[str, Any]:
    index_meta_path = f"{index_path}.meta.json"
    if not Path(index_meta_path).exists():
        raise FileNotFoundError(f"LEANN metadata file not found at {index_meta_path}")

    with open(index_meta_path) as f:
        meta = json.load(f)
    passage_sources = meta.get("passage_sources", [])

    total_passages = 0
    per_field_counts = {field: 0 for field in required_fields}
    full_coverage = 0
    all_fields = set()

    for passage_source in passage_sources:
        with open(passage_source) as f:
            for line_num, line in enumerate(f, 1):
                passage = json.loads(line.strip())
                metadata = passage.get("metadata", {})
                current_fields = set(metadata.keys())

                # Check if all required fields are present in this passage
                if all(field in current_fields for field in required_fields):
                    full_coverage += 1

                # Count each required field occurrence
                for field in required_fields:
                    if field in current_fields:
                        per_field_counts[field] += 1

                # Collect all fields present in any passage
                all_fields.update(current_fields)

                total_passages += 1

    coverage_percentage = (full_coverage / total_passages) * 100 if total_passages != 0 else 0.0
    field_coverage = {
        field: round((count / total_passages) * 100, 2)
        for field, count in per_field_counts.items()
    }

    missing_fields = [field for field in required_fields if field not in all_fields]

    return {
        "coverage_percentage": round(coverage_percentage, 2),
        "field_coverage": field_coverage,
        "missing_fields": missing_fields,
    }

