def export_index_metadata(index_path: str, output_file: str) -> dict[str, Any]:
    meta_path_str = f"{index_path}.meta.json"
    if not Path(meta_path_str).exists():
        raise FileNotFoundError("Index metadata file not found")

    with open(meta_path_str) as f:
        meta = json.load(f)

    passages = []
    for source in meta.get("passage_sources", []):
        source_path = Path(source["path"])
        if not source_path.is_absolute():
            source_path = Path(meta_path_str).parent / source_path
        try:
            with open(source_path) as src_f:
                for line_num, line in enumerate(src_f, 1):
                    try:
                        passage = json.loads(line.strip())
                        passage["line_number"] = line_num  # Optional debug info
                        passages.append(passage)
                    except Exception as e:
                        print(f"Warning: Could not parse passage {line_num}: {e}")
        except FileNotFoundError:
            print(f"Passage source file not found: {source_path}")
            continue

    export_data = {
        "version": meta.get("version", "1.0"),
        "backend_module": meta.get("backend_module"),
        "backend_kwargs": meta.get("backend_kwargs", {}),
        "passages": passages,
    }

    with open(output_file, "w") as f:
        json.dump(export_data, f, indent=2)

    return {
        "exported_passages": len(passages),
        "output_file": output_file,
        "status": "success",
    }


def import_index_from_metadata(
    export_file: str, index_path: str, backend_name: str = "hnsw"
) -> dict[str, Any]:
    if not Path(export_file).exists():
        raise FileNotFoundError("Export file not found")

    with open(export_file) as f:
        data = json.load(f)

    required_keys = {"version", "backend_module", "backend_kwargs", "passages"}
    if not required_keys.issubset(data.keys()):
        raise ValueError("Invalid export file format")

    passages = data["passages"]
    backend_module = data["backend_module"]
    backend_kwargs = data["backend_kwargs"]

    temp_file = Path(index_path).parent / f"{Path(index_path).name}.passages.jsonl"
    with open(temp_file, "w") as f:
        for passage in passages:
            json.dump(passage, f)
            f.write("\n")

    passage_sources = [
        {
            "type": "jsonl",
            "path": str(temp_file),
            # Additional parameters like compression may be missing; assume no compression
        }
    ]

    builder = LeannBuilder(
        passage_sources=passage_sources,
        backend_module=backend_module,
        backend_kwargs=backend_kwargs,
        index_path=index_path,
    )
    builder.build()

    return {
        "index_path": index_path,
        "passages_imported": len(passages),
        "status": "success",
    }

